    changed_at TIMESTAMP, old_email VARCHAR(255)
);

CREATE TRIGGER after_user_update
AFTER UPDATE ON users
FOR EACH ROW
BEGIN
    IF OLD.email != NEW.email THEN
        INSERT INTO users_audit
        VALUES (OLD.id, 'EMAIL_CHANGED', NOW(), OLD.email);
    END IF;
END;

