import time

# Definir un decorator
def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)  # llama la función original
        end = time.time()
        print(f"{func.__name__} tardó {end-start:.2f}s")
        return result
    return wrapper

# Aplicar el decorator
@timer
def process_data(n):
    return sum(range(n))

# Equivalente a: process_data = timer(process_data)
process_data(1_000_000)  # imprime: process_data tardó 0.05s

