from abc import ABC, abstractmethod

# Clase abstracta: define la interfaz
class Shape(ABC):
    @abstractmethod
    def area(self) -> float:
        pass  # Cada subclase DEBE implementarlo

    @abstractmethod
    def perimeter(self) -> float:
        pass

    def describe(self) -> str:  # método concreto
        return f"Area: {self.area():.2f}"

# Implementaciones concretas
class Circle(Shape):
    def __init__(self, radius: float):
        self.radius = radius

    def area(self) -> float:
        return 3.14159 * self.radius ** 2

    def perimeter(self) -> float:
        return 2 * 3.14159 * self.radius

# Shape()  # TypeError: no se puede instanciar clase abstracta
circle = Circle(5)
print(circle.describe())  # Area: 78.54
